const event = $input.first().json.body || $input.first().json;

// Routing rules
const routing = {
  'job_created':      { admin: true, worker: true, client: false },
  'job_assigned':     { admin: false, worker: true, client: true },
  'job_completed':    { admin: true, worker: false, client: true },
  'payment_received': { admin: true, worker: false, client: true },
  'invoice_overdue':  { admin: true, worker: false, client: true },
  'inventory_low':    { admin: true, worker: false, client: false },
  'expense_submitted':{ admin: true, worker: false, client: false },
  'system_alert':     { admin: true, worker: false, client: false }
};

const eventType = event.type || event.event_type || 'system_alert';
const rule = routing[eventType] || { admin: true, worker: false, client: false };

// Build Telegram messages
function buildMsg(role) {
  const emoji = {
    job_created: '\ud83d\udccc', job_assigned: '\u2705', job_completed: '\ud83c\udf1f',
    payment_received: '\ud83d\udcb0', invoice_overdue: '\u26a0\ufe0f',
    inventory_low: '\ud83d\udce6', expense_submitted: '\ud83d\udccb', system_alert: '\ud83d\udea8'
  }[eventType] || '\ud83d\udce2';

  let msg = `${emoji} *${eventType.replace(/_/g, ' ').toUpperCase()}*\n\n`;
  if (event.job_id) msg += `Job: #${event.job_id}\n`;
  if (event.client_name) msg += `Client: ${event.client_name}\n`;
  if (event.worker_name || event.technician_name) msg += `Worker: ${event.worker_name || event.technician_name}\n`;
  if (event.amount) msg += `Amount: $${event.amount}\n`;
  if (event.description) msg += `${event.description}\n`;
  if (event.message) msg += `${event.message}\n`;
  return msg;
}

const telegramAdmin = rule.admin ? buildMsg('admin') : null;
const telegramWorker = rule.worker ? buildMsg('worker') : null;
const telegramClient = rule.client ? buildMsg('client') : null;

return [{ json: {
  eventType,
  channels: { admin: rule.admin, worker: rule.worker, client: rule.client },
  telegramAdmin,
  telegramWorker,
  telegramClient,
  workerChatId: event.telegram_chat_id || event.worker_telegram || null,
  clientChatId: event.client_telegram_id || null
}}];
